// src/App.jsx
import { useState, useEffect } from "react";
import "./styles/global.css";

import Navbar          from "./components/Navbar";
import Hero            from "./components/Hero";
import Features        from "./components/Features";
import PostsSection    from "./components/PostsSection";
import { About, Footer } from "./components/About";
import WriteModal      from "./components/WriteModal";
import PostReader      from "./components/PostReader";
import BookmarksPanel  from "./components/BookmarksPanel";
import FirebaseStatus  from "./components/FirebaseStatus";
import ReadingProgress from "./components/ReadingProgress";
import AuthModal       from "./components/AuthModal";
import UserMenu        from "./components/UserMenu";
import CommunityPage   from "./components/CommunityPage";

import { usePosts }    from "./hooks/usePosts";
import { useDarkMode } from "./hooks/useDarkMode";
import { useAuth }     from "./hooks/useAuth";
import { getBookmarks } from "./firebase/posts";

function LoadingScreen({ done }) {
  return (
    <div style={{
      position: "fixed", inset: 0, zIndex: 9999,
      background: "#0c0c14",
      display: "flex", flexDirection: "column",
      alignItems: "center", justifyContent: "center", gap: 20,
      transition: "opacity 0.6s, visibility 0.6s",
      opacity: done ? 0 : 1, visibility: done ? "hidden" : "visible",
    }}>
      <div style={{
        fontFamily: "var(--font-display)", fontSize: "2.2rem",
        fontWeight: 800, color: "#fff", letterSpacing: "-1px",
        display: "flex", alignItems: "center", gap: 2,
      }}>
        AERO<span style={{ color: "#1d4ed8" }}>BLOG</span>
        <span style={{
          width: 10, height: 10, background: "#f5c518",
          borderRadius: "50%", marginLeft: 4,
          animation: "pulse 1.2s ease-in-out infinite",
        }} />
      </div>
      <div style={{
        width: 200, height: 3, background: "rgba(255,255,255,0.1)",
        borderRadius: 2, overflow: "hidden",
      }}>
        <div style={{
          height: "100%", background: "#1d4ed8", borderRadius: 2,
          animation: "progressFill 1.4s ease forwards",
        }} />
      </div>
      <p style={{
        fontSize: "0.76rem", color: "rgba(255,255,255,0.3)",
        fontFamily: "var(--font-display)", letterSpacing: "0.06em",
        textTransform: "uppercase",
      }}>
        Initialising AI + Firebase…
      </p>
    </div>
  );
}

function Toast({ message, show }) {
  return (
    <div style={{
      position: "fixed", bottom: 24, right: 24, zIndex: 999,
      background: "var(--ink)", color: "#fff",
      padding: "14px 22px", borderRadius: 12,
      fontFamily: "var(--font-display)", fontWeight: 600, fontSize: "0.9rem",
      display: "flex", alignItems: "center", gap: 10,
      boxShadow: "0 8px 30px rgba(0,0,0,0.3)",
      transform: show ? "translateX(0)" : "translateX(130%)",
      opacity: show ? 1 : 0, transition: "all 0.35s ease",
    }}>
      {message || "✅ Done!"}
    </div>
  );
}

export default function App() {
  const [loadingDone,   setLoadingDone]   = useState(false);
  const [showWrite,     setShowWrite]     = useState(false);
  const [selectedPost,  setSelectedPost]  = useState(null);
  const [showBookmarks, setShowBookmarks] = useState(false);
  const [showAuth,      setShowAuth]      = useState(false);
  const [showCommunity, setShowCommunity] = useState(false);
  const [toast,         setToast]         = useState({ show: false, msg: "" });
  const [bookmarkCount, setBookmarkCount] = useState(getBookmarks().length);

  const { posts, loading, isDemo, addDemoPost } = usePosts();
  const [dark, setDark] = useDarkMode();
  const { user, loading: authLoading } = useAuth();

  useEffect(() => { setTimeout(() => setLoadingDone(true), 1600); }, []);

  useEffect(() => {
    if (!showBookmarks && !selectedPost) setBookmarkCount(getBookmarks().length);
  }, [showBookmarks, selectedPost]);

  const showToast = (msg) => {
    setToast({ show: true, msg });
    setTimeout(() => setToast({ show: false, msg: "" }), 3500);
  };

  const handlePublished  = () => showToast("✅ Post published successfully!");
  const handleDemoPublish = (postData) => { addDemoPost(postData); handlePublished(); };

  const handleWriteClick = () => {
    if (!user) { setShowAuth(true); return; }
    setShowWrite(true);
  };

  return (
    <>
      <LoadingScreen done={loadingDone || !authLoading} />
      <ReadingProgress />
      <FirebaseStatus />

      <Navbar
        onWriteClick={handleWriteClick}
        isDemo={isDemo}
        dark={dark}
        onToggleDark={() => setDark((d) => !d)}
        bookmarkCount={bookmarkCount}
        onBookmarksClick={() => setShowBookmarks(true)}
        onCommunityClick={() => setShowCommunity(true)}
        onAuthClick={() => setShowAuth(true)}
        user={user}
      />

      <main style={{ paddingTop: 36 }}>
        <Hero
          postCount={posts.length}
          onWriteClick={handleWriteClick}
          onExplore={() => document.getElementById("posts")?.scrollIntoView({ behavior: "smooth" })}
        />
        <Features />
        <PostsSection
          posts={posts}
          loading={loading}
          isDemo={isDemo}
          onOpenPost={setSelectedPost}
        />
        <About />
      </main>

      <Footer onWriteClick={handleWriteClick} />

      {showWrite && (
        <WriteModal
          onClose={() => setShowWrite(false)}
          onPublished={handlePublished}
          isDemo={isDemo}
          onDemoPublish={handleDemoPublish}
          currentUser={user}
        />
      )}

      {selectedPost && (
        <PostReader
          post={selectedPost}
          onClose={() => { setSelectedPost(null); setBookmarkCount(getBookmarks().length); }}
          isDemo={isDemo}
          currentUser={user}
          allPosts={posts} 
        />
      )}

      {showBookmarks && (
        <BookmarksPanel
          allPosts={posts}
          onOpenPost={(post) => { setShowBookmarks(false); setSelectedPost(post); }}
          onClose={() => setShowBookmarks(false)}
        />
      )}

      {showAuth && (
        <AuthModal
          onClose={() => setShowAuth(false)}
          onSuccess={() => showToast("👋 Welcome to AERO BLOG!")}
        />
      )}

      {showCommunity && (
        <CommunityPage
          onClose={() => setShowCommunity(false)}
          currentUser={user}
          isDemo={isDemo}
        />
      )}

      <Toast show={toast.show} message={toast.msg} />
    </>
  );
}
